const source = $input.first().json.body ?? $input.first().json;
const headers = $input.first().json.headers ?? {};
const authHeader = typeof headers.authorization === 'string' ? headers.authorization.trim() : '';
const expectedToken = $env.MEDIA_WORKER_CALLBACK_TOKEN || '';

if (!expectedToken) {
  return [{ json: { status: 'failed', stage: 'auth', errorCode: 'CALLBACK_AUTH_NOT_CONFIGURED', message: 'MEDIA_WORKER_CALLBACK_TOKEN is not configured in n8n', responseCode: 500, route: 'error' } }];
}
if (authHeader !== `Bearer ${expectedToken}`) {
  return [{ json: { status: 'failed', stage: 'auth', errorCode: 'UNAUTHORIZED_CALLBACK', message: 'worker callback authorization failed', responseCode: 401, route: 'error' } }];
}

const requestId = typeof source.requestId === 'string' && source.requestId.trim() ? source.requestId.trim() : '';
const jobId = typeof source.jobId === 'string' && source.jobId.trim() ? source.jobId.trim() : '';
const workerId = typeof source.workerId === 'string' && source.workerId.trim() ? source.workerId.trim() : '';
const promptId = typeof source.promptId === 'string' && source.promptId.trim() ? source.promptId.trim() : '';
const status = typeof source.status === 'string' ? source.status.trim() : '';
const allowedStatuses = new Set(['completed', 'failed']);
const assetUrls = Array.isArray(source.assetUrls) ? source.assetUrls.filter((v) => typeof v === 'string' && v.trim()) : [];
const outputPath = typeof source.outputPath === 'string' && source.outputPath.trim() ? source.outputPath.trim() : null;
const mimeType = typeof source.mimeType === 'string' && source.mimeType.trim() ? source.mimeType.trim() : null;
const duration = Number.isFinite(Number(source.duration)) ? Number(source.duration) : null;
const sizeBytes = Number.isFinite(Number(source.sizeBytes)) ? Number(source.sizeBytes) : null;
const assets = Array.isArray(source.assets) ? source.assets.filter((asset) => asset && typeof asset === 'object') : [];
const completedAt = typeof source?.timing?.completedAt === 'string' ? source.timing.completedAt : (typeof source.completedAt === 'string' ? source.completedAt : $now.toISO());
const metadata = source.metadata && typeof source.metadata === 'object' ? source.metadata : {};
const error = source.error && typeof source.error === 'object' ? source.error : null;

if (!requestId || !jobId || !workerId || !allowedStatuses.has(status)) {
  return [{ json: { requestId: requestId || null, jobId: jobId || null, status: 'failed', stage: 'validation', errorCode: 'INVALID_CALLBACK_PAYLOAD', message: 'requestId, jobId, workerId, and terminal status are required', responseCode: 400, route: 'error' } }];
}
if (status === 'completed' && assetUrls.length === 0) {
  return [{ json: { requestId, jobId, status: 'failed', stage: 'validation', errorCode: 'MISSING_ASSETS', message: 'completed callback must include assetUrls', responseCode: 400, route: 'error' } }];
}

return [{ json: { requestId, jobId, workerId, promptId, status, assetUrls, outputPath, mimeType, duration, sizeBytes, assets, completedAt, metadata, error, timing: source.timing ?? null, route: 'continue' } }];

const callback = $('Authenticate and Validate Callback').first().json;
const rows = $input.all().filter((item) => item?.json && Object.keys(item.json).length > 0 && item.json.requestId);
const existing = rows[0]?.json;

if (!existing) {
  return [{ json: { requestId: callback.requestId, jobId: callback.jobId, status: 'failed', stage: 'lookup', errorCode: 'JOB_NOT_FOUND', message: 'No Phase 1 job row found for requestId', responseCode: 404, route: 'error' } }];
}
if (existing.jobId && existing.jobId !== callback.jobId) {
  return [{ json: { requestId: callback.requestId, jobId: callback.jobId, status: 'failed', stage: 'lookup', errorCode: 'JOB_ID_MISMATCH', message: 'Callback jobId does not match persisted requestId row', responseCode: 409, route: 'error' } }];
}
const existingStatus = typeof existing.status === 'string' ? existing.status : '';
const terminalStatuses = new Set(['completed', 'failed', 'cancelled']);
if (terminalStatuses.has(existingStatus)) {
  return [{ json: { requestId: existing.requestId, jobId: existing.jobId, status: existing.status, acceptedAt: existing.updatedAtIso || $now.toISO(), duplicateTerminal: true, route: 'duplicate' } }];
}
const resultPayload = {
  status: callback.status,
  workerId: callback.workerId,
  promptId: callback.promptId || null,
  assetUrls: callback.assetUrls,
  outputPath: callback.outputPath,
  mimeType: callback.mimeType,
  duration: callback.duration,
  sizeBytes: callback.sizeBytes,
  assets: callback.assets,
  error: callback.error,
  timing: callback.timing,
  metadata: callback.metadata,
  completedAt: callback.completedAt
};
const updatedAtIso = callback.completedAt || $now.toISO();
return [{ json: {
  requestId: callback.requestId,
  jobId: callback.jobId,
  status: callback.status,
  payloadJson: existing.payloadJson || '',
  resultJson: JSON.stringify(resultPayload),
  updatedAtIso,
  completionPayload: {
    requestId: callback.requestId,
    status: callback.status,
    assetUrls: callback.assetUrls,
    outputPath: callback.outputPath,
    mimeType: callback.mimeType,
    duration: callback.duration,
    sizeBytes: callback.sizeBytes,
    assets: callback.assets,
    metadata: {
      workerId: callback.workerId,
      promptId: callback.promptId || null,
      profile: callback.metadata?.profile || 'acestep_turbo'
    },
    error: callback.error || null
  },
  route: 'update'
} }];

const row = $input.first().json;
const callbackUrl = $env.OPENCLAW_MEDIA_COMPLETION_URL || '';
const callbackToken = $env.OPENCLAW_MEDIA_COMPLETION_TOKEN || '';
let result = {};
try {
  result = row.resultJson ? JSON.parse(row.resultJson) : {};
} catch {}
const completionPayload = {
  requestId: row.requestId,
  jobId: row.jobId,
  status: row.status,
  assetUrls: Array.isArray(result.assetUrls) ? result.assetUrls : [],
  outputPath: result.outputPath || null,
  mimeType: result.mimeType || null,
  duration: result.duration || null,
  sizeBytes: result.sizeBytes || null,
  error: result.error || null,
  timing: result.timing || (result.completedAt ? { completedAt: result.completedAt } : null),
  metadata: {
    ...(result.metadata && typeof result.metadata === 'object' ? result.metadata : {}),
    workerId: result.workerId || null,
    promptId: result.promptId || null,
    profile: result.metadata?.profile || 'acestep_turbo'
  }
};
return [{ json: { ...row, completionPayload, notifyConfigured: Boolean(callbackUrl && callbackToken), notifyUrl: callbackUrl } }];
